patch:
diff --git a/llvm/lib/Transforms/InstCombine/InstCombineSelect.cpp b/llvm/lib/Transforms/InstCombine/InstCombineSelect.cpp
index 5a42a5c996da..4951e33c5213 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineSelect.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineSelect.cpp
@@ -3929,16 +3929,28 @@ Instruction *InstCombinerImpl::visitSelectInst(SelectInst &SI) {
       if (match(&SI, m_OrdOrUnordFMax(m_Value(X), m_Value(Y)))) {
         Value *BinIntr =
             Builder.CreateBinaryIntrinsic(Intrinsic::maxnum, X, Y, &SI);
-        if (auto *BinIntrInst = dyn_cast<Instruction>(BinIntr))
-          BinIntrInst->setHasNoNaNs(FCmp->hasNoNaNs());
+        if (auto *BinIntrInst = dyn_cast<Instruction>(BinIntr)) {
+          // Start from the FMF that IRBuilder applied (copied from the select),
+          // but adjust NaN/Inf flags to match the compare. This avoids
+          // unintentionally strengthening semantics: select's FMF does not
+          // constrain operands, but minnum/maxnum do.
+          FastMathFlags FMF = BinIntrInst->getFastMathFlags();
+          FMF.setNoNaNs(FCmp && FCmp->hasNoNaNs());
+          FMF.setNoInfs(FCmp && FCmp->hasNoInfs());
+          BinIntrInst->copyFastMathFlags(FMF);
+        }
         return replaceInstUsesWith(SI, BinIntr);
       }

       if (match(&SI, m_OrdOrUnordFMin(m_Value(X), m_Value(Y)))) {
         Value *BinIntr =
             Builder.CreateBinaryIntrinsic(Intrinsic::minnum, X, Y, &SI);
-        if (auto *BinIntrInst = dyn_cast<Instruction>(BinIntr))
-          BinIntrInst->setHasNoNaNs(FCmp->hasNoNaNs());
+        if (auto *BinIntrInst = dyn_cast<Instruction>(BinIntr)) {
+          FastMathFlags FMF = BinIntrInst->getFastMathFlags();
+          FMF.setNoNaNs(FCmp && FCmp->hasNoNaNs());
+          FMF.setNoInfs(FCmp && FCmp->hasNoInfs());
+          BinIntrInst->copyFastMathFlags(FMF);
+        }
         return replaceInstUsesWith(SI, BinIntr);
       }
     }

